// TIPS HOME
const tips = [
  "Travel during the off-season to save money.",
  "Use public transportation instead of taxis.",
  "Book flights early for better prices.",
  "Compare accommodation options before booking."
];
const tipBtn = document.getElementById("welcomeBtn");
const tipOutput = document.getElementById("tipOutput");
if(tipBtn){ tipBtn.addEventListener("click", ()=>{ tipOutput.textContent = tips[Math.floor(Math.random()*tips.length)]; }); }

// DESTINATIONS DATA
const destinations = [
  { name:"Mexico", location:"Mexico City, Mexico", budget:800, description:"Affordable food and beaches.", imageUrl:"https://encrypted-tbn0.gstatic.com/licensed-image?q=tbn:ANd9GcRwCAkukmL48eQFLeR0KVQ5q1gYkcQZtN8Bz4bFkERPbJIiJKy-GqRhkli-AZxg1L8Y85Gc5u6HVglMeCp1kHLkmsU&s=19" },
  { name:"Colombia", location:"Bogotá, Colombia", budget:750, description:"Colorful cities, low costs.", imageUrl:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRC2-HwsnTN6mKLP99W9wrB00bD5NB8BQvlaA&s" },
  { name:"Portugal", location:"Lisbon, Portugal", budget:900, description:"Europe charm at lower cost.", imageUrl:"data:image/jpeg;base64," },
  { name:"Thailand", location:"Bangkok, Thailand", budget:700, description:"Amazing food and beaches.", imageUrl:"data:image/jpeg;base64," },
  { name:"Vietnam", location:"Hanoi, Vietnam", budget:650, description:"Rich culture, delicious street food.", imageUrl:"data:image/jpeg;base64," },
  { name:"Morocco", location:"Marrakech, Morocco", budget:800, description:"Exotic markets, desert adventures.", imageUrl:"data:image/jpeg;base64," }
];

const container = document.getElementById("destinationsContainer");
if(container){
  container.innerHTML = destinations.map(d=>`
    <div class="destination-card">
      <img src="${d.imageUrl}" alt="${d.name}" loading="lazy">
      <h3>${d.name}</h3>
      <p>${d.location}</p>
      <p>${d.description}</p>
      <div>
        <span class="budget">$${d.budget}</span>
        <span class="badge">${d.budget<800?"Low Budget":"Moderate"}</span>
      </div>
    </div>
  `).join("");
}

// TRIP PLANNER + LOCALSTORAGE
const form = document.getElementById("tripForm");
const savedTripDiv = document.getElementById("savedTrip");
if(form){
  form.addEventListener("submit", e=>{
    e.preventDefault();
    const destination=document.getElementById("destination").value.trim();
    const budget=Number(document.getElementById("budget").value);
    if(budget<100){ alert(`${destination} requires a realistic budget above $100.`); return; }
    const trips = JSON.parse(localStorage.getItem("trips")||"[]");
    trips.push({destination,budget});
    localStorage.setItem("trips",JSON.stringify(trips));
    displayTrips();
    form.reset();
  });
}
function displayTrips(){
  const trips=JSON.parse(localStorage.getItem("trips")||"[]");
  if(savedTripDiv){
    savedTripDiv.innerHTML = trips.map(t=>`
      <div class="destination-card">
        <h3>${t.destination}</h3>
        <p>Budget: $${t.budget}</p>
      </div>
    `).join("");
  }
}
displayTrips();

